const filters = {
  time_window: null,
  category: null,
  keywords: [],
  size: 1000
};
const options = {
  style_version: "Neutral",
  sentiment_target: "None"
};
const query = { match_all: {} };
return [{ json: {
  filters,
  options,
  opensearch_query: {
    size: filters.size,
    _source: ['id', 'title', 'body', 'source', 'published_at', 'language'],
    query,
    sort: [{ published_at: { order: 'desc' }}]
  }
}}];

const hits = $json.hits?.hits ?? [];
const articles = hits.map(h => h._source).filter(a => a && a.body);
const MAX_BODY_LENGTH = 5000;
const processed = articles.map(a => {
  if (a.body.length > MAX_BODY_LENGTH) {
    return { ...a, body: a.body.substring(0, MAX_BODY_LENGTH), body_truncated: true };
  }
  return { ...a, body_truncated: false };
});
console.log(`📊 Processing ${processed.length} articles (body max: ${MAX_BODY_LENGTH} chars)`);
return processed.map(a => ({ json: a }));

const items = $input.all().map(i => i.json);
const pad2 = n => String(n).padStart(2, '0');
const pad3 = n => String(n).padStart(3, '0');
const now = new Date();
const datePart = `${now.getFullYear()}-${pad2(now.getMonth()+1)}-${pad2(now.getDate())}_${pad2(now.getHours())}${pad2(now.getMinutes())}`;
const requestId = `n8n_start_${datePart}_${pad3($runIndex+1)}`;
const filterData = $('Build OpenSearch Query').first().json;
const filters = filterData?.filters || {};
const options = filterData?.options || {};
const articleIds = items.map(a => a.id).filter(Boolean);
const articles = items.map(a => ({
  id: a.id || "",
  url: a.url || a.id,
  title: a.title || "",
  body: a.body || "",
  language: a.language || "en",
  source: a.source || "",
  published_at: a.published_at || null,
  category: "general"
}));

if (articles.length > 100) throw new Error(`Too many: ${articles.length}`);
if (articles.length === 0) throw new Error('No articles');

console.log(`✅ BATCH ${$runIndex + 1}: ${articles.length} articles`);

return [{
  json: {
    llm_payload: {
      request_id: requestId,
      filters_used: filters,
      articles: articles
    },
    llm_batch_record: {
      request_id: requestId,
      filters_used: filters,
      options: options,
      article_ids: articleIds,
      article_count: articles.length,
      status: "pending",
      ingested_at: new Date().toISOString(),
      trigger_type: "start",
      llm_endpoint: "/summarize_clustered",
      output_index: "news_cluster_summaries",
      retry_count: 0,
      current_batch_size: articles.length
    }
  }
}];

// ERROR BRANCH - Split into smaller batches and retry
const preservedData = $json;

console.log(`🔍 Preserved data keys: ${Object.keys(preservedData).join(', ')}`);

// DEFENSIVE: Support both structures
const batchData = preservedData.batch_data;
const payload = preservedData.payload;

// Validate we have the required data
if (!batchData) {
  console.log(`❌ No batch_data found. Available keys: ${Object.keys(preservedData).join(', ')}`);
  return [{
    json: {
      error: true,
      message: "Missing batch_data",
      skipped: true
    }
  }];
}

if (!payload) {
  console.log(`❌ No payload found. Available keys: ${Object.keys(preservedData).join(', ')}`);
  return [{
    json: {
      error: true,
      message: "Missing payload",
      skipped: true
    }
  }];
}

if (!payload.articles) {
  console.log(`❌ No articles in payload. Payload keys: ${Object.keys(payload).join(', ')}`);
  return [{
    json: {
      error: true,
      message: "Missing articles in payload",
      skipped: true
    }
  }];
}

const originalArticles = payload.articles;
const retryCount = batchData.retry_count || 0;
const currentSize = batchData.current_batch_size;

console.log(`❌ TIMEOUT: Batch failed with ${currentSize} articles. Retry count: ${retryCount}`);

// Max retry check
if (retryCount >= 3) {
  console.log(`⚠️ Max retries reached. Skipping this batch.`);
  return [{
    json: {
      error: true,
      error_type: "max_retry_exceeded", 
      message: "Max retries reached",
      request_id: batchData.request_id,
      skipped: true,
      batch_info: {
        original_size: batchData.article_count,
        final_size: currentSize,
        retry_count: retryCount,
        article_ids: batchData.article_ids
      }
    }
  }];
}

// AGGRESSIVE BODY TRIMMING on retry
const maxBodyLength = Math.max(1000, 5000 - (retryCount * 1500));
console.log(`✂️ Trimming article bodies to ${maxBodyLength} chars for retry ${retryCount + 1}`);

// Trim articles before splitting
const trimmedArticles = originalArticles.map(a => {
  const body = a.body || "";
  if (body.length > maxBodyLength) {
    return {
      ...a,
      body: body.substring(0, maxBodyLength),
      body_trimmed: true,
      original_length: body.length
    };
  }
  return { ...a, body_trimmed: false };
});

// Calculate new batch size (split into thirds)
const newBatchSize = Math.max(5, Math.floor(currentSize / 3));
console.log(`🔄 Splitting batch: ${currentSize} → ${newBatchSize} articles (1/3 size)`);

// Split articles into smaller chunks
const subBatches = [];
for (let i = 0; i < trimmedArticles.length; i += newBatchSize) {
  subBatches.push(trimmedArticles.slice(i, i + newBatchSize));
}

console.log(`📦 Created ${subBatches.length} sub-batches with ${maxBodyLength} char limit`);

// Return sub-batches as separate items
return subBatches.map((articles, idx) => {
  const subRequestId = `${batchData.request_id}_retry${retryCount + 1}_sub${idx + 1}`;

  const totalChars = articles.reduce((sum, a) => sum + (a.body?.length || 0), 0);
  console.log(`  Sub-batch ${idx + 1}: ${articles.length} articles, ${totalChars} total chars`);

  return {
    json: {
      llm_payload: {
        request_id: subRequestId,
        filters_used: batchData.filters_used,
        articles: articles
      },
      llm_batch_record: {
        request_id: subRequestId,
        parent_request_id: batchData.parent_request_id || batchData.request_id,
        filters_used: batchData.filters_used,
        options: batchData.options,
        article_ids: articles.map(a => a.id).filter(Boolean),
        article_count: articles.length,
        status: "pending_retry",
        ingested_at: new Date().toISOString(),
        trigger_type: "retry",
        llm_endpoint: "/summarize_clustered",
        output_index: "news_cluster_summaries",
        retry_count: retryCount + 1,
        current_batch_size: articles.length,
        original_batch_size: currentSize,
        body_max_length: maxBodyLength
      }
    }
  };
});

// Prepare data for retry LLM call
const splitRetryOutput = $input.item.json;

console.log(`📥 Prepare Retry - Input keys: ${Object.keys(splitRetryOutput).join(', ')}`);

const llmPayload = splitRetryOutput.llm_payload;
const llmBatchRecord = splitRetryOutput.llm_batch_record;

if (!llmPayload || !llmBatchRecord) {
  console.log(`❌ Missing required data from Split and Retry`);
  return [{
    json: {
      error: true,
      message: "Invalid data from Split and Retry"
    }
  }];
}

console.log(`✅ Retry prepared: ${llmPayload.request_id}, ${llmPayload.articles.length} articles`);

// Return both so Preserve node can access batch_record
return [{
  json: {
    llm_payload: llmPayload,
    llm_batch_record: llmBatchRecord
  }
}];

const wrapper = $json;
let resp = wrapper.llm_response ?? wrapper;
if (typeof resp === "string") {
  try { resp = JSON.parse(resp); } catch { resp = {}; }
}

const request_id = resp.request_id || "";
const processed_at = resp.processed_at || new Date().toISOString();
let clusters = resp.clusters || [];

if (typeof clusters === "string") {
  try { 
    clusters = JSON.parse(clusters); 
  } catch (e) { 
    clusters = []; 
  }
}

const cluster_count = Array.isArray(clusters) ? clusters.length : 0;
const mega_summary = resp.mega_summary || "";

// DEFENSIVE FIX: Get original articles with IDs from payload
const originalPayload = wrapper.payload;
const originalArticles = originalPayload?.articles || [];

// Create a title-to-article map for ID lookup
const titleToArticleMap = {};
originalArticles.forEach(article => {
  const normalizedTitle = (article.title || "").trim().toLowerCase();
  if (normalizedTitle && article.id) {
    titleToArticleMap[normalizedTitle] = article;
  }
});

console.log(`✅ Creating ${cluster_count} cluster documents`);
console.log(`📋 Original articles for ID mapping: ${originalArticles.length}`);

return (Array.isArray(clusters) ? clusters : []).map(c => {
  // Deduplicate articles by title
  const uniqueArticlesMap = {};
  (c.articles || []).forEach(a => {
    const title = (a.title || "").trim();
    const normalizedTitle = title.toLowerCase();

    if (title && !uniqueArticlesMap[normalizedTitle]) {
      // Try to get ID from LLM response first, then fallback to original payload
      let articleId = a.id || a.article_id || "";

      // DEFENSIVE: If LLM didn't provide ID, look it up from original payload
      if (!articleId && titleToArticleMap[normalizedTitle]) {
        articleId = titleToArticleMap[normalizedTitle].id;
        console.log(`  🔍 Mapped ID for "${title.substring(0, 50)}...": ${articleId}`);
      }

      uniqueArticlesMap[normalizedTitle] = {
        id: a.url,
        url: a.url || "",
        title: title
      };
    }
  });

  const uniqueArticles = Object.values(uniqueArticlesMap);

  console.log(`  Cluster ${c.cluster_id}: ${(c.articles || []).length} articles → ${uniqueArticles.length} unique (with IDs)`);

  return {
    json: {
      id: `${request_id}_c${c.cluster_id}`,
      request_id: request_id,
      summary_type: "clustered_summary",
      processed_at: processed_at,
      cluster_count: cluster_count,
      mega_summary: mega_summary,
      cluster_id: c.cluster_id,
      category: c.category || "",
      subcategory: c.subcategory || "",
      topic_summary: c.topic_summary || "",
      article_count: uniqueArticles.length,
      articles: uniqueArticles,
      processing_time: resp.processing_time || 0
    }
  };
});

const llmResponse = $json;

let prepareRetryData = [];
try {
  prepareRetryData = $('Prepare Retry Data').all();
} catch (e) {
  prepareRetryData = [];
}

let batchData;
if (prepareRetryData && prepareRetryData.length > 0) {
  batchData = prepareRetryData[0].json.llm_batch_record;
} else {
  batchData = $('Prepare Batch').item.json.llm_batch_record;
}

return [{
  json: {
    request_id: batchData.request_id,
    update: {
      status: "completed",
      processed_at: new Date().toISOString(),
      processing_time: llmResponse.processing_time || 0,
      cluster_count: llmResponse.cluster_count || 0
    }
  }
}];

const llmResponse = $json;


const batch = $json.llm_batch_record || $json.batch_data;
const payload = $json.llm_payload || $json.payload;

let fallback = null;
if (!batch || !payload) {
  try { fallback = $items("Prepare Retry Data", 0, 0)[0].json; } catch {}
}

const finalBatch = batch || fallback?.llm_batch_record;
const finalPayload = payload || fallback?.llm_payload;

return [{
  json: {
    llm_response: llmResponse,
    batch_data: finalBatch,
    payload: finalPayload,
    error: llmResponse?.error || null,
    has_error: !!llmResponse.error ? "true" : "false"
  }
}];

//const prepareBatch = $('Prepare Batch').item.json;

const llmResponse = $json;
const payload = $json.llm_payload;
const batchData = $json.llm_batch_record;

return [{
  json: {
    llm_response: llmResponse,
    batch_data: batchData,
    payload: payload,
    error: llmResponse.error || null,  
    has_error: !!llmResponse.error ? "true" : "false"
  }
}];
